(v_test_id, 1, 'Physics', 'Q1', 'A car accelerates from rest at a constant rate $\alpha$ for some time after which it decelerates at a constant rate $\beta$ to come to rest. If the total time elapsed is $t$, then the maximum velocity acquired by the car is given by', NULL, 'mcq-single', '[{"id":0,"text":"$\\left(\\dfrac{\\alpha^{2}+\\beta^{2}}{\\alpha\\beta}\\right)t$"},{"id":1,"text":"$\\left(\\dfrac{\\alpha^{2}-\\beta^{2}}{\\alpha\\beta}\\right)t$"},{"id":2,"text":"$\\left(\\dfrac{\\alpha+\\beta}{\\alpha\\beta}\\right)t$"},{"id":3,"text":"$\\left(\\dfrac{\\alpha\\beta}{\\alpha+\\beta}\\right)t$"}]'::jsonb, to_jsonb(3), NULL, 0, 4, -1, 0, false),
(v_test_id, 2, 'Physics', 'Q2', 'A body is thrown vertically upwards. Which one of the following graphs correctly represents the velocity vs time?', 'https://zmkgboiqubtowmionplq.supabase.co/storage/v1/object/public/site-content/tests/rt03/phy-q2.png', 'mcq-single', '[{"id":0,"text":"Graph (A)"},{"id":1,"text":"Graph (B)"},{"id":2,"text":"Graph (C)"},{"id":3,"text":"Graph (D)"}]'::jsonb, to_jsonb(3), NULL, 0, 4, -1, 0, false),
(v_test_id, 3, 'Physics', 'Q3', 'Find acceleration of the moving body from the given graph (where $V$ = velocity and $S$ = displacement).', 'https://zmkgboiqubtowmionplq.supabase.co/storage/v1/object/public/site-content/tests/rt03/phy-q3.png', 'mcq-single', '[{"id":0,"text":"$0.5\\ \\text{m/s}^2$"},{"id":1,"text":"$0.2\\ \\text{m/s}^2$"},{"id":2,"text":"$1\\ \\text{m/s}^2$"},{"id":3,"text":"$0\\ \\text{m/s}^2$"}]'::jsonb, to_jsonb(0), NULL, 0, 4, -1, 0, false),
(v_test_id, 4, 'Physics', 'Q4', 'A particle starts from rest and moves with constant acceleration. Its velocity–displacement curve is:', 'https://zmkgboiqubtowmionplq.supabase.co/storage/v1/object/public/site-content/tests/rt03/phy-q4.png', 'mcq-single', '[{"id":0,"text":"Curve (A)"},{"id":1,"text":"Curve (B)"},{"id":2,"text":"Curve (C)"},{"id":3,"text":"Curve (D)"}]'::jsonb, to_jsonb(1), NULL, 0, 4, -1, 0, false),
(v_test_id, 5, 'Physics', 'Q5', 'Two bodies are projected with the same velocity. If one is projected at an angle of $30^\circ$ and the other at $60^\circ$ to the horizontal, the ratio of the maximum heights reached is:', NULL, 'mcq-single', '[{"id":0,"text":"$3:1$"},{"id":1,"text":"$1:3$"},{"id":2,"text":"$1:2$"},{"id":3,"text":"$2:1$"}]'::jsonb, to_jsonb(1), NULL, 0, 4, -1, 0, false),
(v_test_id, 6, 'Physics', 'Q6', 'The velocity of a projectile at the initial point $A$ is $\vec{u}=(2\hat{i}+3\hat{j})$ m/s. Its velocity (in m/s) at point $B$ is:', 'https://zmkgboiqubtowmionplq.supabase.co/storage/v1/object/public/site-content/tests/rt03/phy-q6.png', 'mcq-single', '[{"id":0,"text":"$(2\\hat{i}+3\\hat{j})$ m/s"},{"id":1,"text":"$(-2\\hat{i}-3\\hat{j})$ m/s"},{"id":2,"text":"$(-2\\hat{i}+3\\hat{j})$ m/s"},{"id":3,"text":"$(2\\hat{i}-3\\hat{j})$ m/s"}]'::jsonb, to_jsonb(3), NULL, 0, 4, -1, 0, false),
(v_test_id, 7, 'Physics', 'Q7', 'A particle is projected with velocity $u$ at an angle $\theta$ with the horizontal. The time after which the acceleration vector and velocity vector become perpendicular to each other during the path is', NULL, 'mcq-single', '[{"id":0,"text":"$\\dfrac{u\\sin\\theta}{g}$"},{"id":1,"text":"$\\dfrac{u\\cos\\theta}{g}$"},{"id":2,"text":"$\\dfrac{2u\\sin\\theta}{g}$"},{"id":3,"text":"$\\dfrac{2u\\cos\\theta}{g}$"}]'::jsonb, to_jsonb(0), NULL, 0, 4, -1, 0, false),
(v_test_id, 8, 'Physics', 'Q8', 'During projectile motion the acceleration of a particle at the highest point of its trajectory is', NULL, 'mcq-single', '[{"id":0,"text":"$g$"},{"id":1,"text":"zero"},{"id":2,"text":"less than $g$"},{"id":3,"text":"dependent upon projection velocity"}]'::jsonb, to_jsonb(0), NULL, 0, 4, -1, 0, false),
(v_test_id, 9, 'Physics', 'Q9', 'If a projectile is thrown such that the range $R$ is four times the height $h$ attained, then the angle of projection is:', NULL, 'mcq-single', '[{"id":0,"text":"$30^\\circ$"},{"id":1,"text":"$45^\\circ$"},{"id":2,"text":"$60^\\circ$"},{"id":3,"text":"$90^\\circ$"}]'::jsonb, to_jsonb(1), NULL, 0, 4, -1, 0, false),
(v_test_id, 10, 'Physics', 'Q10', 'A water fountain on the ground sprinkles water all around it. If the speed of water coming out is $v$, the total area around the fountain that gets wet is:', NULL, 'mcq-single', '[{"id":0,"text":"$\\pi\\dfrac{v^{2}}{g}$"},{"id":1,"text":"$\\pi\\dfrac{v^{4}}{g^{2}}$"},{"id":2,"text":"$\\pi\\dfrac{v^{4}}{2g^{2}}$"},{"id":3,"text":"$\\pi\\dfrac{v^{2}}{g^{2}}$"}]'::jsonb, to_jsonb(1), NULL, 0, 4, -1, 0, false),
