(v_test_id, 16, 'Physics', 'Q16', 'The resultant of $\vec{P}$ and $\vec{Q}$ is $\vec{R}$. If $\vec{Q}$ is doubled, $\vec{R}$ is doubled; when $\vec{Q}$ is reversed, $\vec{R}$ is again doubled. Find $P:Q:R$', NULL, 'mcq-single', '[{"id":0,"text":"$\\sqrt{3}:\\sqrt{6}:\\sqrt{4}$"},{"id":1,"text":"$\\sqrt{4}:\\sqrt{2}:\\sqrt{3}$"},{"id":2,"text":"$\\sqrt{2}:\\sqrt{3}:\\sqrt{2}$"},{"id":3,"text":"$\\sqrt{3}:\\sqrt{4}:\\sqrt{2}$"}]'::jsonb, to_jsonb(2), NULL, 0, 4, -1, 0, false),
